{
  "case_id": "zhoufang_xingmang_qingxin_2026_0215",
  "parties": {
    "victim": "周芳",
    "perpetrator": "星芒传媒",
    "witness": "赵敏"
  },
  "evidence_items": [
    {
      "id": "E1",
      "type": "official_vs_mcn_data_discrepancy",
      "description": "小红书官方后台播放量为 50,234，MCN 报告给品牌方为 120,000，约 2.39x。",
      "verified": true
    },
    {
      "id": "E2",
      "type": "api_definition_conflict",
      "description": "小红书官方 API 明确 note.views 是唯一官方播放统计口径，曝光量 note.impressions 与播放量为独立指标，刘姐的全渠道曝光量解释不成立。",
      "verified": true
    },
    {
      "id": "E3",
      "type": "admission",
      "description": "刘姐微信承认：好吧...有些数据是我们内部估算的，不完全是后台导出。但行业里大家都这么做。品牌方也知道MCN的数据会有一定的放大。这不是只有我们一家这样。",
      "verified": true
    },
    {
      "id": "E4",
      "type": "contract_noncompliance",
      "description": "合同要求 verified data，但品牌方收到的是 PDF 报告、PNG 截图和 MCN 自制 Excel，未提供 API 导出或经验证第三方监测报告。",
      "verified": true
    },
    {
      "id": "E5",
      "type": "financial_damage_pattern",
      "description": "赵敏 upd4 微信材料显示，小林创作者实际合同金额 30,000，MCN 实际向品牌方收取 70,000，约 2.33x。",
      "verified": true
    }
  ],
  "financial_damage": {
    "contract_amount": 30000,
    "actual_billed": 70000,
    "overcharge_ratio": 2.33
  },
  "legal_threshold_met": true
}

